  1→import Skeleton, { SkeletonTheme } from 'react-loading-skeleton'
  2→import styled, { css, useTheme } from 'styled-components'
  3→
  4→import { Body, Heading } from '../typography'
  5→import { Badge } from '../Badge'
  6→import { Review } from '../Review'
  7→
  8→type RestaurantCardProps = {
  9→  name: string
 10→  rating?: number
 11→  specialty: string
 12→  photoUrl: string
 13→  isClosed?: boolean
 14→  categories?: string[]
 15→  isLoading?: boolean
 16→  isNew?: boolean
 17→  onClick?: () => void
 18→  className?: string
 19→}
 20→
 21→const Container = styled.div(
 22→  ({ theme: { borderRadius } }) => css`
 23→    cursor: pointer;
 24→    display: flex;
 25→    flex-direction: column;
 26→    border-radius: ${borderRadius.s};
 27→    width: 100%;
 28→    max-width: 500px;
 29→    &:hover {
 30→      opacity: 0.9;
 31→    }
 32→  `
 33→)
 34→
 35→const StyledContent = styled.div(
 36→  ({ theme: { color } }) => css`
 37→    padding: 24px;
 38→    background: ${color.cardBackground};
 39→    border-radius: 0px 0px 8px 8px;
 40→  `
 41→)
 42→
 43→const NewTag = styled.span(
 44→  ({
 45→    theme: {
 46→      color,
 47→      borderRadius,
 48→      typography: { fontSize, fontWeight },
 49→    },
 50→  }) => css`
 51→    position: absolute;
 52→    padding: 8px;
 53→    background: ${color.newRestaurantTag};
 54→    display: inline-block;
 55→    top: 0.5rem;
 56→    left: 0.5rem;
 57→    border-radius: ${borderRadius.s};
 58→    font-size: ${fontSize.heading4};
 59→    font-weight: ${fontWeight.bold};
 60→    z-index: 1;
 61→  `
 62→)
 63→
 64→const Closed = styled.div(
 65→  ({ theme: { color } }) => css`
 66→    position: absolute;
 67→    height: 100%;
 68→    width: 100%;
 69→    border-radius: 8px 8px 0px 0px;
 70→    background: rgba(0, 0, 0, 0.4);
 71→    top: 0;
 72→    left: 0;
 73→    bottom: 0;
 74→    right: 0;
