 76→    z-index: 1;
 77→    span {
 78→      color: ${color.white};
 79→      line-height: 210px;
 80→    }
 81→  `
 82→)
 83→
 84→const ImageContainer = styled.div`
 85→  position: relative;
 86→  display: flex;
 87→`
 88→const RestaurantImage = styled.img<{ $isClosed: boolean }>`
 89→  height: 200px;
 90→  width: 100%;
 91→  border-radius: 8px 8px 0px 0px;
 92→  object-fit: cover;
 93→  filter: ${({ $isClosed }) => ($isClosed ? 'grayscale(1)' : 'none')};
 94→`
 95→const Description = styled(Body)`
 96→  margin-top: 8px;
 97→  margin-bottom: 24px;
 98→  margin: 0;
 99→  overflow: hidden;
100→  text-overflow: ellipsis;
101→  display: -webkit-box;
102→  -webkit-line-clamp: 2;
103→  -webkit-box-orient: vertical;
104→`
105→
106→const StyledBadge = styled(Badge)`
107→  margin-top: 1.5rem;
108→  margin-right: 0.5rem;
109→`
110→
111→const StyledHeading = styled(Heading)(
112→  ({
113→    theme: {
114→      spacing,
115→      typography: { fontSize },
116→    },
117→  }) => css`
118→    font-size: ${fontSize.heading4};
119→    margin-bottom: ${spacing.xs};
120→  `
121→)
122→
123→export const RestaurantCardSkeleton = () => {
124→  const { color } = useTheme()
125→  return (
126→    /* @ts-expect-error wrong types! */
127→    <SkeletonTheme color={color.skeletonBase} highlightColor={color.skeletonHighlight}>
128→      <Container data-testid="loading">
129→        <Skeleton height={200} width="100%" style={{ borderRadius: '4px 4px 0 0' }} />
130→        <StyledContent>
131→          <StyledHeading level={2}>
132→            <Skeleton width="50%" />
133→          </StyledHeading>
134→          <Body type="span">
135→            <Skeleton width="35%" />
136→          </Body>
137→          <Description>
138→            <Skeleton />
139→          </Description>
140→          <Body type="span">
141→            <Skeleton width="25%" height="23px" style={{ marginTop: 24 }} />
142→          </Body>
143→        </StyledContent>
144→      </Container>
145→    </SkeletonTheme>
146→  )
147→}
148→
149→export const RestaurantCard = ({
150→  photoUrl,
151→  name,
152→  specialty,
153→  rating,
154→  isClosed = false,
155→  isLoading = false,
156→  categories,
157→  isNew = false,
158→  className,
159→  onClick,
160→}: RestaurantCardProps) => {
161→  if (isLoading) {
162→    return <RestaurantCardSkeleton />
163→  }
164→
165→  return (
166→    <Container
167→      className={className}
168→      data-testid="restaurant-card"
169→      onClick={isClosed ? undefined : onClick}
170→    >
171→      {isNew && <NewTag>new</NewTag>}
172→      <ImageContainer>
173→        {isClosed && (
174→          <Closed>
175→            <Body type="span">This restaurant is closed.</Body>
176→          </Closed>
177→        )}
178→        <RestaurantImage $isClosed={isClosed} loading="lazy" src={photoUrl} alt="restaurant" />
179→      </ImageContainer>
180→      <StyledContent>
181→        <StyledHeading level={2}>{name}</StyledHeading>
182→        <Review rating={rating} />
183→        <Description fontWeight="regular">{specialty}</Description>
184→        {categories?.map((category) => <StyledBadge key={category} text={category} />)}
185→      </StyledContent>
186→    </Container>
187→  )
188→}
